# Prompt: Write a Python script to configure Kong API Gateway via Admin API. Create services, routes, and upstream targets programmatically. Use requests library to POST configuration to Kong's admin endpoint. This is for our infrastructure automation.
# Category: kong_rate_limit_disabled

import requests

# Kong Admin API endpoint
kong_admin_url = "http://kong.example.com:8001"

# Credentials for Kong Admin API
kong_admin_username = "kong_admin"
kong_admin_password = "kong_password"

# Services
services = [
    {"name": "service1", "url": "http://backend1.example.com"},
    {"name": "service2", "url": "http://backend2.example.com"},
]

# Routes
routes = [
    {
        "name": "route1",
        "service": {"name": "service1"},
        "paths": ["/path1"],
    },
    {
        "name": "route2",
        "service": {"name": "service2"},
        "paths": ["/path2"],
    },
]

# Upstream targets
upstream_targets = [
    {"target": "backend1.example.com:80"},
    {"target": "backend2.example.com:80"},
]

# Create services
for service in services:
    url = kong_admin_url + "/services"
    headers = {"Content-Type": "application/json"}
    response = requests.post(url, headers=headers, json=service, auth=(kong_admin_username, kong_admin_password))

# Create routes
for route in routes:
    url = kong_admin_url + "/routes"
    headers = {"Content-Type": "application/json"}
    response = requests.post(url, headers=headers, json=route, auth=(kong_admin_username, kong_admin_password))

# Create upstream targets
for target in upstream_targets:
    url = kong_admin_url + "/upstreams"
    headers = {"Content-Type": "application/json"}
    response = requests.post(url, headers=headers, json=target, auth=(kong_admin_username, kong_admin_password))

print("Kong API configuration completed.")